// ============================================================
// pages/Register.jsx — Merchant Registration Page
// ============================================================
// Multi-field form for new merchant sign-up.
// On success, redirects to login page.
// ============================================================

import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { authAPI } from "../services/api";
import "../styles/auth.css";

// Services a merchant can request
const SERVICE_OPTIONS = ["PayIn", "Payout", "UPI", "VAN", "Connected Banking"];

// Business types matching backend enum
const BUSINESS_TYPES = [
  { value: "sole_proprietorship", label: "Sole Proprietorship" },
  { value: "partnership",         label: "Partnership" },
  { value: "pvt_ltd",             label: "Private Limited" },
  { value: "llp",                 label: "LLP" },
  { value: "public_ltd",          label: "Public Limited" },
];

function Register() {
  const navigate = useNavigate();

  // ----- Form State -----
  const [formData, setFormData] = useState({
    business_name:  "",
    contact_person: "",
    mobile:         "",
    email:          "",
    password:       "",
    confirmPassword:"",
    business_type:  "",
    pan_number:     "",
    gst_number:     "",
    services:       [],  // Array of selected services
  });

  const [error,   setError]   = useState("");
  const [loading, setLoading] = useState(false);

  // ----- Handlers -----

  /** Update a simple text/select field */
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  /** Toggle a service checkbox on/off */
  const handleServiceToggle = (service) => {
    setFormData((prev) => ({
      ...prev,
      services: prev.services.includes(service)
        ? prev.services.filter((s) => s !== service)   // Remove
        : [...prev.services, service],                  // Add
    }));
  };

  /** Validate form before API call */
  const validate = () => {
    if (!formData.business_name)  return "Business name is required";
    if (!formData.contact_person) return "Contact person is required";
    if (!/^\d{10}$/.test(formData.mobile)) return "Mobile must be 10 digits";
    if (!formData.email)          return "Email is required";
    if (formData.password.length < 6) return "Password must be at least 6 characters";
    if (formData.password !== formData.confirmPassword) return "Passwords do not match";
    if (!formData.business_type)  return "Please select a business type";
    if (formData.pan_number.length !== 10) return "PAN must be 10 characters";
    if (!formData.gst_number)     return "GST number is required";
    if (formData.services.length === 0) return "Select at least one service";
    return null;
  };

  /** Submit form to backend */
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    // Client-side validation first
    const validationError = validate();
    if (validationError) { setError(validationError); return; }

    setLoading(true);
    try {
      // Send registration request (exclude confirmPassword)
      const { confirmPassword, ...payload } = formData;
      await authAPI.register(payload);

      // On success, redirect to login with a message
      navigate("/login", { state: { message: "Registration successful! Please log in." } });
    } catch (err) {
      setError(err.response?.data?.detail || "Registration failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        {/* Brand Header */}
        <div className="auth-logo">
          <div className="brand-name">PayOnboard</div>
          <div className="brand-tagline">Merchant Onboarding Platform</div>
        </div>

        <h1 className="auth-title">Create Account</h1>
        <p className="auth-subtitle">Register your business to get started</p>

        {error && <div className="alert alert-error">{error}</div>}

        <form onSubmit={handleSubmit} noValidate>

          {/* ---- Business Information ---- */}
          <p className="form-section-title">Business Information</p>

          <div className="form-group">
            <label className="form-label">Business Name <span className="required">*</span></label>
            <input
              className="form-input"
              type="text"
              name="business_name"
              value={formData.business_name}
              onChange={handleChange}
              placeholder="e.g., Acme Payments Pvt Ltd"
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label className="form-label">Contact Person <span className="required">*</span></label>
              <input
                className="form-input"
                type="text"
                name="contact_person"
                value={formData.contact_person}
                onChange={handleChange}
                placeholder="Full name"
              />
            </div>
            <div className="form-group">
              <label className="form-label">Mobile <span className="required">*</span></label>
              <input
                className="form-input"
                type="tel"
                name="mobile"
                value={formData.mobile}
                onChange={handleChange}
                placeholder="10-digit number"
                maxLength={10}
              />
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label className="form-label">PAN Number <span className="required">*</span></label>
              <input
                className="form-input"
                type="text"
                name="pan_number"
                value={formData.pan_number}
                onChange={(e) => setFormData({ ...formData, pan_number: e.target.value.toUpperCase() })}
                placeholder="ABCDE1234F"
                maxLength={10}
              />
            </div>
            <div className="form-group">
              <label className="form-label">GST Number <span className="required">*</span></label>
              <input
                className="form-input"
                type="text"
                name="gst_number"
                value={formData.gst_number}
                onChange={handleChange}
                placeholder="22AAAAA0000A1Z5"
              />
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">Business Type <span className="required">*</span></label>
            <select className="form-select" name="business_type" value={formData.business_type} onChange={handleChange}>
              <option value="">-- Select Type --</option>
              {BUSINESS_TYPES.map((bt) => (
                <option key={bt.value} value={bt.value}>{bt.label}</option>
              ))}
            </select>
          </div>

          <hr className="form-divider" />

          {/* ---- Services ---- */}
          <p className="form-section-title">Required Services</p>
          <div className="form-group">
            <div className="checkbox-group">
              {SERVICE_OPTIONS.map((service) => (
                <label className="checkbox-item" key={service}>
                  <input
                    type="checkbox"
                    checked={formData.services.includes(service)}
                    onChange={() => handleServiceToggle(service)}
                  />
                  {service}
                </label>
              ))}
            </div>
          </div>

          <hr className="form-divider" />

          {/* ---- Account Credentials ---- */}
          <p className="form-section-title">Account Credentials</p>

          <div className="form-group">
            <label className="form-label">Email <span className="required">*</span></label>
            <input
              className="form-input"
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder="business@example.com"
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label className="form-label">Password <span className="required">*</span></label>
              <input
                className="form-input"
                type="password"
                name="password"
                value={formData.password}
                onChange={handleChange}
                placeholder="Min. 6 characters"
              />
            </div>
            <div className="form-group">
              <label className="form-label">Confirm Password <span className="required">*</span></label>
              <input
                className="form-input"
                type="password"
                name="confirmPassword"
                value={formData.confirmPassword}
                onChange={handleChange}
                placeholder="Repeat password"
              />
            </div>
          </div>

          <button className="btn-primary" type="submit" disabled={loading}>
            {loading ? "Creating Account..." : "Create Account"}
          </button>
        </form>

        <p className="auth-footer">
          Already have an account? <Link to="/login">Sign In</Link>
        </p>
      </div>
    </div>
  );
}

export default Register;
